#include <string>

class Base
{
public:
    // TODO: the runtime-checked downcast in main can only query a POLYMORPHIC
    // type -- a class with at least one virtual function. As written, Base has
    // none, so the cast below will not even compile. What single member should
    // Base declare to make it polymorphic? (The conventional choice for a base
    // class also makes deletion through Base* safe.)
};

class Derived : public Base
{
public:
    std::string special() const { return "I am Derived"; }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{ 0 }; i < n; ++i)
    {
        std::string type{};
        std::cin >> type; // "base" or "derived"

        Base* ptr{ nullptr };
        if (type == "derived")
            ptr = new Derived{};
        else
            ptr = new Base{};

        // The runtime-checked downcast is already written for you -- it only
        // compiles once Base is polymorphic (see the TODO in Base above).
        Derived* dp{ dynamic_cast<Derived*>(ptr) };
        if (dp)
            std::cout << "Cast succeeded: " << dp->special() << '\n';
        else
            std::cout << "Cast failed: base object" << '\n';

        delete ptr;
    }

    return 0;
}

